const SALT: &[u8] = b"synatyp-association-salt-2026";
const NONCE: &[u8; 12] = b"unique-nonce"; // Matching .env

const AI_ENCRYPTED_KEY: &[u8] = &[139, 61, 106, 177, 154, 109, 124, 236, 131, 205, 138, 212, 107, 216, 202, 218, 142, 5, 38, 66, 214, 189, 82, 149, 62, 161, 240, 39, 11, 135, 30, 210, 244, 10, 156, 152, 81, 217, 98, 92, 144, 142, 226, 203, 173, 13, 132, 117, 237, 108, 236, 165, 97, 72, 73];

pub fn derive_key(password: &str) -> [u8; 32] {
    let mut key = [0u8; 32];
    pbkdf2::<Hmac<Sha256>>(password.as_bytes(), SALT, 100_000, &mut key).expect("PBKDF2 failed");
    key
}

#[tauri::command]
pub async fn unlock_models(password: String) -> Result<Templates, String> {
    let key = derive_key(&password);
    let cipher = Aes256Gcm::new_from_slice(&key).map_err(|e| e.to_string())?;
    let mut nonce = aes_gcm::aead::generic_array::GenericArray::<u8, aes_gcm::aead::consts::U12>::default();
    nonce.copy_from_slice(NONCE);

    let plaintext = cipher.decrypt(&nonce, ENCRYPTED_DATA).map_err(|_| "Mot de passe incorrect".to_string())?;
    let templates: Templates = serde_json::from_slice(&plaintext).map_err(|e| e.to_string())?;
    
    Ok(templates)
}

pub fn get_decrypted_ai_key(password: &str) -> Option<String> {
    let key = derive_key(password);
    let cipher = Aes256Gcm::new_from_slice(&key).ok()?;
    let mut nonce = aes_gcm::aead::generic_array::GenericArray::<u8, aes_gcm::aead::consts::U12>::default();
    nonce.copy_from_slice(NONCE);

    let plaintext = cipher.decrypt(&nonce, AI_ENCRYPTED_KEY).ok()?;
    String::from_utf8(plaintext).ok()
}
